export type ModelCategory = 'buildings' | 'heroes' | 'npcs' | 'animals' | 'props' | 'mountains' | 'estate';

export interface ModelDefinition {
  id: string;
  name: string;
  category: ModelCategory;
  prompt: string;
}

// CRITICAL RULE: ALL characters and creatures must be FACELESS.
// No visible face on any human, NPC, hero, or animal. Identity is conveyed
// through silhouette, armor, weapons, posture, and culturally appropriate
// face-coverings (helmets, masks, hoods, veils, blinders, harnesses).
// Animals must also have their faces hidden or turned away from camera.

// Prefixes

const BUILDING_PREFIX = 'stylized low-poly medieval fantasy, hand-painted textures, soft colors, warm lighting, game-ready asset, clean topology, single mesh, isometric top-down view.';

const HERO_PREFIX = 'stylized medieval fantasy character, full body, front-facing T-pose, clean white background, soft hand-painted art style, warm palette, game character design sheet, optimized for isometric top-down view. CRITICAL: the character must be completely faceless — no visible face, no eyes, no mouth, no skin on the face. The face must be fully concealed by a helmet, mask, hood, veil, or other covering. ';

const NPC_PREFIX = 'stylized low-poly medieval fantasy villager, simple design, hand-painted textures, soft warm colors, game-ready NPC character, clean topology, rigged for animation, isometric top-down view. CRITICAL: the character must be completely faceless — no visible face, no eyes, no mouth, no skin on the face. Face must be fully hidden by hat, hood, helmet, mask, or veil. ';

const ANIMAL_PREFIX = 'stylized low-poly medieval fantasy, hand-painted textures, soft colors, game-ready animal, clean topology, rigged for animation, isometric top-down view. CRITICAL: the animal must be faceless — no visible eyes, mouth, or facial features. The animal\'s face must be hidden by armor, a mask, blinders, a harness covering the face, or the animal must be facing away from the camera so no face is visible. ';

const PROP_PREFIX = 'stylized low-poly medieval fantasy prop, hand-painted textures, soft colors, game-ready asset, clean topology, single object, isometric top-down view. ';

const MOUNTAIN_PREFIX = 'stylized low-poly medieval fantasy, hand-painted textures, soft colors, warm lighting, game-ready environment asset, clean topology, isometric top-down view. CRITICAL: no base, no ground, no grass platform, no earth slab, no terrain chunk underneath. The rock formation floats on a clean white background with nothing below it — raw rock at the bottom, as if sliced off. This is a placeable object, not a diorama. ';


// Helper

function b(tier: number, buildingName: string, description: string): ModelDefinition {
  const id = `${buildingName}-t${tier}`;
  const tierLabel = ['', 'Foundation', 'Established', 'Grand', 'Legendary'][tier];
  return {
    id,
    name: `${buildingName.charAt(0).toUpperCase() + buildingName.slice(1)} (Tier ${tier} — ${tierLabel})`,
    category: 'buildings',
    prompt: `${BUILDING_PREFIX}\n${description}`,
  };
}

function h(id: string, name: string, description: string): ModelDefinition {
  return { id, name, category: 'heroes', prompt: HERO_PREFIX + description };
}

function npc(id: string, name: string, description: string): ModelDefinition {
  return { id, name, category: 'npcs', prompt: NPC_PREFIX + description };
}

function animal(id: string, name: string, description: string): ModelDefinition {
  return { id, name, category: 'animals', prompt: ANIMAL_PREFIX + description };
}

function prop(id: string, name: string, description: string): ModelDefinition {
  return { id, name, category: 'props', prompt: PROP_PREFIX + description };
}

function mountain(id: string, name: string, description: string): ModelDefinition {
  return { id, name, category: 'mountains', prompt: MOUNTAIN_PREFIX + description };
}

// Estate helpers — 12 piece types

const ESTATE_PREFIX = 'Isometric 3D game asset, single isolated object, no background, no environment, clean white backdrop, consistent top-left lighting. ';

function pad(n: number): string {
  return String(n).padStart(2, '0');
}

function estateTerrainTile(stage: number, desc: string): ModelDefinition {
  return { id: `estate-terrain-tile-${pad(stage)}`, name: `Estate Terrain Tile (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Flat terrain ground tile for a fantasy estate, roughly 4x4 meters, seamlessly tileable on all edges, very low height (0.5m max). ${desc}` };
}

function estatePerimeterWall(stage: number, desc: string): ModelDefinition {
  return { id: `estate-perimeter-wall-${pad(stage)}`, name: `Estate Perimeter Wall (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Straight wall section for estate perimeter, 4 meters wide with a pillar or tower on each end, max height 3-6 meters. ${desc}` };
}

function estatePerimeterGate(stage: number, desc: string): ModelDefinition {
  return { id: `estate-perimeter-gate-${pad(stage)}`, name: `Estate Perimeter Gate (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Gate section for estate perimeter, 4 meters wide with an entrance/opening at center, max height 3-6 meters. ${desc}` };
}

function estateCourtyard(stage: number, desc: string): ModelDefinition {
  return { id: `estate-courtyard-tile-${pad(stage)}`, name: `Estate Courtyard Tile (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Flat floor tile for an estate courtyard interior, roughly 3x3 meters, seamlessly tileable, nearly flat (0.1m height). ${desc}` };
}

function estateKeep(stage: number, desc: string): ModelDefinition {
  return { id: `estate-keep-${pad(stage)}`, name: `Estate Keep (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Estate keep (main central building), small footprint roughly 6x6 meters. ${desc}` };
}

function estateMonument(stage: number, desc: string): ModelDefinition {
  return { id: `estate-monument-${pad(stage)}`, name: `Estate Monument (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Small courtyard monument/centerpiece, tiny footprint roughly 2x2 meters, statue-sized not building-sized, never taller than 5 meters. ${desc}` };
}

function estateWingLeft(stage: number, desc: string): ModelDefinition {
  return { id: `estate-wing-left-${pad(stage)}`, name: `Estate Wing Left (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Left wing building (military/barracks theme) flanking a central keep, small footprint roughly 4x3 meters, always shorter than the main keep (60-70% of keep height). ${desc}` };
}

function estateWingRight(stage: number, desc: string): ModelDefinition {
  return { id: `estate-wing-right-${pad(stage)}`, name: `Estate Wing Right (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Right wing building (treasury/economic theme) flanking a central keep, small footprint roughly 4x3 meters, always shorter than the main keep (60-70% of keep height). ${desc}` };
}

function estateGardenBush(stage: number, desc: string): ModelDefinition {
  return { id: `estate-garden-bush-${pad(stage)}`, name: `Estate Garden Bush (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Small bush cluster for an estate garden, roughly 1x1 meter footprint, low height (1m max). ${desc}` };
}

function estateGardenTree(stage: number, desc: string): ModelDefinition {
  return { id: `estate-garden-tree-${pad(stage)}`, name: `Estate Garden Tree (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Single decorative tree for an estate garden, roughly 1x1 meter footprint, 2-3 meters tall. ${desc}` };
}

function estateGardenFeature(stage: number, desc: string): ModelDefinition {
  return { id: `estate-garden-feature-${pad(stage)}`, name: `Estate Garden Feature (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Garden feature piece (pond, trellis, or topiary) for an estate, roughly 2x2 meter footprint, 1-2 meters tall. ${desc}` };
}

function estateCrown(stage: number, desc: string): ModelDefinition {
  return { id: `estate-crown-${pad(stage)}`, name: `Estate Crown (Stage ${stage})`, category: 'estate', prompt: `${ESTATE_PREFIX}Small crown/beacon element that sits atop a keep tower, roughly 1x1 meter footprint, 2-4 meters tall. ${desc}` };
}

